[package]
name = "vos-kernel"
version = "0.1.0"
edition = "2024"

# 该 crate 以 “ArceOS 外部应用” 形式存在：
# - 它不进入 `arceos/` workspace，避免污染上游式目录布局；
# - 它通过 path 依赖显式引用仓库内 `axstd`，从而满足比赛“随仓提供源码”的约束；
# - 它是当前比赛根级 `make all` 的真实构建入口，而不是 `arceos/examples/*`。

[dependencies]
# `optional = true` 与 ArceOS 自带示例保持一致。
# ArceOS 的 Makefile 会把 `axstd/defplat`、`axstd/log-level-*` 等特性通过
# `--features` 注入到应用 crate，因此这里必须允许按 feature 条件开启 `axstd`。
axstd = { path = "../arceos/ulib/axstd", optional = true }
axhal = { path = "../arceos/modules/axhal", optional = true }
axcpu = { version = "0.3", optional = true }
axlog = { path = "../arceos/modules/axlog", optional = true }
axmm = { path = "../arceos/modules/axmm", optional = true }
axalloc = { path = "../arceos/modules/axalloc", optional = true }
axfs = { path = "../arceos/modules/axfs", optional = true }
axio = { version = "0.2", optional = true }
axfs_devfs = { version = "0.1", optional = true }
axfs_ramfs = { path = "../third_party/rust/vendor/axfs_ramfs", optional = true }
axfs_vfs = { version = "0.1", optional = true }
crate_interface = { version = "0.3", optional = true }
axnet = { path = "../arceos/modules/axnet", optional = true }
ext4-view = { path = "../third_party/rust/vendor/ext4-view-0.9.2", optional = true }
memory_addr = { version = "0.4", optional = true }
riscv = { version = "0.16", optional = true }
page_table_entry = { version = "0.6", optional = true }
axerrno = { version = "0.2", optional = true }
linkme = { version = "0.3", optional = true }
lazyinit = { version = "0.2", optional = true }
axdriver = { path = "../arceos/modules/axdriver", optional = true }
axsync = { path = "../arceos/modules/axsync", optional = true }

[patch.crates-io]
axcpu = { path = "../third_party/rust/vendor/axcpu" }
axfs_ramfs = { path = "../third_party/rust/vendor/axfs_ramfs" }
axfs_vfs = { path = "../third_party/rust/vendor/axfs_vfs" }
axplat-riscv64-qemu-virt = { path = "../third_party/rust/vendor/axplat-riscv64-qemu-virt" }
axplat-loongarch64-qemu-virt = { path = "../third_party/rust/vendor/axplat-loongarch64-qemu-virt" }

[target.'cfg(target_arch = "riscv64")'.dependencies]
axplat-riscv64-qemu-virt = { version = "0.4", features = ["smp", "irq"], optional = true }

[target.'cfg(target_arch = "loongarch64")'.dependencies]
axplat-loongarch64-qemu-virt = { version = "0.4", features = ["smp", "irq"], optional = true }

[features]
default = ["axstd"]
axstd = [
    "dep:axstd",
    "dep:axhal",
    "dep:axcpu",
    "dep:axlog",
    "dep:axmm",
    "dep:axalloc",
    "dep:axfs",
    "dep:axio",
    "dep:axfs_devfs",
    "dep:axfs_ramfs",
    "dep:axfs_vfs",
    "dep:crate_interface",
    "dep:axnet",
    "dep:ext4-view",
    "dep:memory_addr",
    "dep:riscv",
    "dep:page_table_entry",
    "dep:axerrno",
    "dep:linkme",
    "dep:lazyinit",
    "dep:axdriver",
    "dep:axsync",
    "axstd/myfs",
    "axhal/uspace",
]
riscv64-qemu-virt = ["dep:axplat-riscv64-qemu-virt"]
loongarch64-qemu-virt = ["dep:axplat-loongarch64-qemu-virt"]

#![cfg_attr(feature = "axstd", no_std)]
#![cfg_attr(feature = "axstd", no_main)]

// 这个 crate 不是常规 Linux 用户态程序，而是作为 ArceOS “外部应用” 链接进
// `axruntime`。因此：
// - 开启 `axstd` 时需要 `no_std + no_main`；
// - 真正的底层启动、内存和驱动初始化由 ArceOS 运行时先完成；
// - 本文件只声明模块边界，并把控制流转交给 `init::run_minimal_loop()`。

#[cfg(feature = "axstd")]
#[macro_use]
extern crate axstd as std;

#[cfg(all(target_arch = "loongarch64", feature = "loongarch64-qemu-virt"))]
extern crate axplat_loongarch64_qemu_virt;
#[cfg(all(target_arch = "riscv64", feature = "riscv64-qemu-virt"))]
extern crate axplat_riscv64_qemu_virt;

#[cfg(feature = "axstd")]
mod arch;
#[cfg(feature = "axstd")]
mod exec;
#[cfg(feature = "axstd")]
mod fs;
#[cfg(feature = "axstd")]
mod init;
#[cfg(feature = "axstd")]
mod syscall;
#[cfg(feature = "axstd")]
mod task;
#[cfg(feature = "axstd")]
mod trap;
#[cfg(feature = "axstd")]
mod user;

#[cfg(feature = "axstd")]
#[unsafe(no_mangle)]
/// ArceOS 外部应用入口。
///
/// 运行时完成底层初始化后，会把控制流交给这里；本 crate 再继续把启动职责转交给
/// `init::run_minimal_loop()`，保持 `main.rs` 只承担模块装配与顶层入口职责。
fn main() {
    init::run_minimal_loop();
}

//! 比赛 bring-up 的最小启动控制流。
//!
//! 当前阶段把启动编排收敛到一条最窄的比赛闭环：
//! 1. 挂载 ext4 评测盘并列出根目录条目，确认根盘可读；
//! 2. 从根目录或官方 runtime 目录枚举可识别的测试组；
//! 3. 对每个测试组按顺序装载并执行对应用户程序；
//! 4. 直接 ELF 组由内核补打比赛要求的 `START/END` 标记；
//! 5. 每组子程序 `exit` 后恢复父线程拿到 `wait4` 返回，再由内核 continuation 决定继续下一组或关机。
//!
//! 这里仍然刻意不做完整 shell 解释；多组调度只覆盖当前最有价值的计分组。

use axerrno::{LinuxError, LinuxResult};
use axhal::context::UspaceContext;
use axstd::string::{String, ToString};
use axstd::sync::Arc;
use axstd::vec::Vec;
use axsync::Mutex;
use core::fmt::Write;
use memory_addr::{MemoryAddr, PAGE_SIZE_4K, va};
use page_table_entry::MappingFlags;

use crate::exec::{
    ExecSpec, OFFICIAL_RUNTIME_ROOTS, build_official_runtime_envp, install_exec, load_exec_image,
};
use crate::fs::{RootDirEntry, RootFsProvider, VfsRoot, build_vfs_root};
use crate::task::{
    CurrentThread, Thread, WaitOutcome, allocator_watermark, clear_exit_continuation,
    enqueue_runnable, ensure_kernel_init_process, install_exit_continuation, schedule_in, take_last_wait_outcome,
};
use crate::user::user_trap_stack_top;

/// 比赛测试组发现脚本的文件名后缀。
const TESTCODE_SUFFIX: &str = "_testcode.sh";
/// 测试盘里用户程序所在目录。
const BIN_DIR: &str = "/bin";
/// 官方 LTP 组名。
const LTP_GROUP_NAME: &str = "ltp";
/// 官方 libctest 组名。
const LIBCTEST_GROUP_NAME: &str = "libctest";
/// 官方 iperf 组名。
const IPERF_GROUP_NAME: &str = "iperf";
/// 当前 focused bring-up 放开的官方测试组，逗号分隔。
///
/// 默认值是“评测平台干净 build（不经仓库 Makefile、不注入该 env）”时编译期落入的兜底。
/// 当前无 env 的正式构建和本地 official runner 默认都放开
/// `basic,busybox,libcbench,libctest,lmbench,lua,ltp,iozone,iperf,netperf`；其中
/// `libctest` 只在 musl runtime 放行，
/// `ltp` 仍通过内核内置 case 白名单收口，避免默认全量超时。
/// 本地需要更窄的短跑时应显式注入更小的 focused group。
const OFFICIAL_FOCUSED_GROUPS: &str = match option_env!("VOS_OFFICIAL_FOCUSED_GROUPS") {
    Some(groups) => groups,
    None => "basic,busybox,libcbench,libctest,lmbench,lua,ltp,iozone,iperf,netperf",
};
/// 当前 focused bring-up 放开的官方 runtime，逗号分隔；默认跑全部 runtime。
const OFFICIAL_FOCUSED_RUNTIMES: &str = match option_env!("VOS_OFFICIAL_FOCUSED_RUNTIMES") {
    Some(runtimes) => runtimes,
    None => "all",
};
/// LTP 短跑精确 case 白名单，逗号分隔。
///
/// 为空且 prefix/limit 也为空时使用内置线上白名单；传 `all` / `full` / `*` 时关闭内置白名单。
const LTP_CASES_FILTER: &str = match option_env!("VOS_LTP_CASES") {
    Some(cases) => cases,
    None => "",
};
/// LTP 短跑 case 前缀白名单，逗号分隔；为空时不过滤。
const LTP_CASE_PREFIXES_FILTER: &str = match option_env!("VOS_LTP_CASE_PREFIXES") {
    Some(prefixes) => prefixes,
    None => "",
};
/// LTP 短跑最大 case 数；为空或非法时不过滤。
const LTP_CASE_LIMIT: &str = match option_env!("VOS_LTP_CASE_LIMIT") {
    Some(limit) => limit,
