//! 项目侧最小架构 ABI 胶水。
//!
//! 这层只负责收口“当前目标架构的 trap frame 字段名”和“syscall 返回后 PC
//! 应当前推多少字节”这两类差异，业务 syscall 实现不直接感知 RV64 / LA64。

use axhal::context::TrapFrame;

/// 从 trap frame 解码出的最小 syscall ABI 视图。
#[derive(Clone, Copy, Debug)]
pub struct ArchSyscallAbi {
    pub nr: usize,
    pub args: [usize; 6],
}

/// 返回当前架构下 trap frame 中保存的用户态 frame pointer。
pub fn trap_frame_pointer(tf: &TrapFrame) -> usize {
    frame_pointer(tf)
}

/// 返回当前架构下一条用户态指令地址。
pub fn next_syscall_ip(tf: &TrapFrame) -> usize {
    trap_ip(tf) + 4
}

/// 从 trap frame 读取统一的 syscall ABI。
pub fn decode_syscall_abi(tf: &TrapFrame) -> ArchSyscallAbi {
    ArchSyscallAbi {
        nr: tf.regs.a7,
        args: [
            tf.arg0(),
            tf.arg1(),
            tf.arg2(),
            tf.arg3(),
            tf.arg4(),
            tf.arg5(),
        ],
    }
}

#[cfg(target_arch = "riscv64")]
fn trap_ip(tf: &TrapFrame) -> usize {
    tf.sepc
}

#[cfg(target_arch = "loongarch64")]
fn trap_ip(tf: &TrapFrame) -> usize {
    tf.era
}

#[cfg(target_arch = "riscv64")]
fn frame_pointer(tf: &TrapFrame) -> usize {
    tf.regs.s0
}

#[cfg(target_arch = "loongarch64")]
fn frame_pointer(tf: &TrapFrame) -> usize {
    tf.regs.fp
}

