/// 一次允许被 signal 提前打断的阻塞 syscall 等待窗口。
#[derive(Clone, Copy, Debug)]
pub(super) struct InterruptibleBlock {
    deadline: Option<Duration>,
}

impl InterruptibleBlock {
    pub(super) const fn new(deadline: Option<Duration>) -> Self {
        Self { deadline }
    }
}

/// 阻塞 syscall 被 signal 打断后暴露给用户态的最小返回形状。
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub(super) enum InterruptedSyscallResult {
    Eintr,
}

impl InterruptedSyscallResult {
    pub(super) const fn into_linux_error(self) -> LinuxError {
        match self {
            Self::Eintr => LinuxError::EINTR,
        }
    }
}

/// deadline 等待中一次“完成 / 超时 / 被 signal 打断”的共享等待结果。
#[derive(Debug)]
pub(super) enum SignalAwareDeadlineWait<T> {
    Complete(T),
    TimedOut,
    Interrupted(InterruptedSyscallResult),
}

pub(super) fn wait_with_signal_deadline<T>(
    current: &Thread,
    block: InterruptibleBlock,
    mut try_complete: impl FnMut() -> Result<Option<T>, LinuxError>,
    mut on_idle: impl FnMut(),
) -> Result<SignalAwareDeadlineWait<T>, LinuxError> {
    loop {
        if crate::task::should_interrupt_interruptible_block(current) {
            return Ok(SignalAwareDeadlineWait::Interrupted(
                InterruptedSyscallResult::Eintr,
            ));
        }
        if let Some(result) = try_complete()? {
            return Ok(SignalAwareDeadlineWait::Complete(result));
        }
        if block
            .deadline
            .is_some_and(|deadline| axhal::time::wall_time() >= deadline)
        {
            return Ok(SignalAwareDeadlineWait::TimedOut);
        }
        on_idle();
    }
}

