pub(crate) const LARGE_USER_BUFFER_BYTES: usize = 4 * 1024 * 1024;

/// 以可失败方式分配一个零填充内核缓冲；堆不足时返回 `ENOMEM` 而不是 panic。
pub(crate) fn try_alloc_zeroed_buf(size: usize) -> axerrno::LinuxResult<axstd::vec::Vec<u8>> {
    let mut buf = axstd::vec::Vec::new();
    buf.try_reserve_exact(size)
        .map_err(|_| axerrno::LinuxError::ENOMEM)?;
    buf.resize(size, 0);
    Ok(buf)
}

