#[must_use]
pub(crate) struct CapacityLimitedRamfsWriteGuard {
    bytes: usize,
}

impl CapacityLimitedRamfsWriteGuard {
    fn none() -> Self {
        Self { bytes: 0 }
    }
}

impl Drop for CapacityLimitedRamfsWriteGuard {
    fn drop(&mut self) {
        if self.bytes == 0 {
            return;
        }
        let previous =
            CAPACITY_LIMITED_RAMFS_IN_FLIGHT_BYTES.fetch_sub(self.bytes, Ordering::AcqRel);
        debug_assert!(previous >= self.bytes);
        self.bytes = 0;
    }
}

