/// Linux RISC-V 用户态 `struct linux_dirent64`。
#[repr(C)]
#[derive(Clone, Copy, Debug, Default)]
struct LinuxTimespec {
    tv_sec: i64,
    tv_nsec: i64,
}

impl LinuxTimespec {
    /// 从内核 `Duration` 生成 Linux 用户态 `timespec`。
    fn from_duration(duration: core::time::Duration) -> Self {
        Self {
            tv_sec: duration.as_secs() as i64,
            tv_nsec: duration.subsec_nanos() as i64,
        }
    }

    /// 从带符号纳秒值生成 Linux 用户态 `timespec`。
    fn from_signed_nanos(nanos: i128) -> Self {
        let tv_sec = nanos.div_euclid(1_000_000_000);
        let tv_nsec = nanos.rem_euclid(1_000_000_000);
        Self {
            tv_sec: tv_sec.clamp(i64::MIN as i128, i64::MAX as i128) as i64,
            tv_nsec: tv_nsec as i64,
        }
    }

    /// 把 Linux 用户态 `timespec` 转成内核 `Duration`。
    fn to_duration(self) -> Result<core::time::Duration, LinuxError> {
        if self.tv_sec < 0 || self.tv_nsec < 0 || self.tv_nsec >= 1_000_000_000 {
            return Err(LinuxError::EINVAL);
        }
        Ok(core::time::Duration::new(
            self.tv_sec as u64,
            self.tv_nsec as u32,
        ))
    }
}

