/// 进程级最小 scheduler 兼容状态。
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub(crate) struct SchedCompatState {
    pub(crate) policy: i32,
    pub(crate) priority: i32,
    pub(crate) affinity_mask: u64,
    pub(crate) reset_on_fork: bool,
    pub(crate) runtime_ns: u64,
    pub(crate) deadline_ns: u64,
    pub(crate) period_ns: u64,
}

impl Default for SchedCompatState {
    fn default() -> Self {
        Self {
            policy: 0,
            priority: 0,
            affinity_mask: 1,
            reset_on_fork: false,
            runtime_ns: 0,
            deadline_ns: 0,
            period_ns: 0,
        }
    }
}

impl SchedCompatState {
    fn fork_child_state(self) -> Self {
        if self.reset_on_fork && matches!(self.policy, 1 | 2) {
            return Self {
                policy: 0,
                priority: 0,
                affinity_mask: self.affinity_mask,
                reset_on_fork: false,
                runtime_ns: 0,
                deadline_ns: 0,
                period_ns: 0,
            };
        }
        Self {
            reset_on_fork: false,
            ..self
        }
