impl ThreadComm {
    pub(crate) fn from_str_lossy(value: &str) -> Self {
        let mut bytes = [0; THREAD_COMM_LEN];
        let src = value.as_bytes();
        let len = src.len().min(THREAD_COMM_LEN - 1);
        bytes[..len].copy_from_slice(&src[..len]);
        Self { bytes }
    }

    pub(crate) const fn bytes(&self) -> &[u8; THREAD_COMM_LEN] {
        &self.bytes
    }

    pub(crate) fn as_str(&self) -> &str {
        let len = self
            .bytes
            .iter()
            .position(|byte| *byte == 0)
            .unwrap_or(THREAD_COMM_LEN);
        core::str::from_utf8(&self.bytes[..len]).unwrap_or("vos")
    }
}

