static STDIO_WRITE_LOCK: Mutex<()> = Mutex::new(());
const STDIO_LINE_BUFFER_LIMIT: usize = PAGE_SIZE_4K;

fn stdio_fd_kind(fd: i32) -> Option<StdioKind> {
    match fd {
        1 => Some(StdioKind::Stdout),
        2 => Some(StdioKind::Stderr),
        _ => None,
    }
}

fn canonical_stdio_fd(kind: StdioKind) -> Option<i32> {
    match kind {
        StdioKind::Stdin => None,
        StdioKind::Stdout => Some(1),
        StdioKind::Stderr => Some(2),
    }
}

fn flush_stdio_line_buffer_locked(entry: &mut StdioLineBufferEntry) {
    if entry.bytes.is_empty() {
        return;
    }
    let _guard = STDIO_WRITE_LOCK.lock();
    axhal::console::write_bytes(&entry.bytes);
    entry.bytes.clear();
}

fn append_stdio_line_bytes(tid: super::Tid, fd: i32, data: &[u8]) {
    if data.is_empty() {
        return;
    }
    let mut entries = STDIO_LINE_BUFFERS.lock();
    let entry = if let Some(entry) = entries
        .iter_mut()
        .find(|entry| entry.tid == tid && entry.fd == fd)
    {
        entry
    } else {
        entries.push(StdioLineBufferEntry {
            tid,
            fd,
            bytes: Vec::new(),
        });
        entries.last_mut().unwrap()
    };
    for &byte in data {
        entry.bytes.push(byte);
        if byte == b'\n' {
            flush_stdio_line_buffer_locked(entry);
        }
    }
    if entry.bytes.len() >= STDIO_LINE_BUFFER_LIMIT {
        flush_stdio_line_buffer_locked(entry);
    }
}

fn flush_stdio_line_buffer_for(tid: super::Tid, fd: i32) {
    let mut entries = STDIO_LINE_BUFFERS.lock();
    if let Some(index) = entries
        .iter()
        .position(|entry| entry.tid == tid && entry.fd == fd)
    {
        flush_stdio_line_buffer_locked(&mut entries[index]);
        if entries[index].bytes.is_empty() {
            entries.swap_remove(index);
        }
    }
}

pub(crate) fn flush_all_stdio_line_buffers_for_tid(tid: super::Tid) {
    let mut entries = STDIO_LINE_BUFFERS.lock();
    let mut index = 0usize;
    while index < entries.len() {
        if entries[index].tid == tid {
            flush_stdio_line_buffer_locked(&mut entries[index]);
            entries.swap_remove(index);
        } else {
            index += 1;
        }
    }
}
