/// `wait4(2)` 当前支持的最小目标选择器。
#[derive(Clone, Copy)]
pub enum WaitTarget {
    /// 等待任意直接子进程。
    Any,
    /// 等待指定 pid 的直接子进程。
    Pid(Pid),
    /// 等待指定进程组中的任意直接子进程，严格按进程组匹配。
    ProcessGroup(Pid),
}

/// wait 目标当前的可回收状态。
pub enum WaitAvailability {
    Ready(WaitOutcome),
    WouldBlock,
}

/// 用户态 wait 系列 syscall 的完成写回方式。
#[derive(Clone, Copy)]
pub enum WaitCompletion {
    /// `wait4(2)` / `waitpid(2)` 风格：写 raw wait status，返回子进程 pid。
    Wait4 {
        status_ptr: usize,
        want_stopped: bool,
        want_continued: bool,
    },
    /// `waitid(2)` 风格：写 `siginfo_t`，成功返回 0。
    WaitId {
        siginfo_ptr: usize,
        no_reap: bool,
        want_exited: bool,
        want_stopped: bool,
        want_continued: bool,
    },
}

impl WaitCompletion {
    const fn reaps_child(self) -> bool {
        match self {
            Self::Wait4 { .. } => true,
            Self::WaitId { no_reap, .. } => !no_reap,
        }
    }

    const fn wants_exited(self) -> bool {
        match self {
            Self::Wait4 { .. } => true,
            Self::WaitId { want_exited, .. } => want_exited,
        }
    }

    const fn wants_stopped(self) -> bool {
        match self {
            Self::Wait4 { want_stopped, .. } => want_stopped,
            Self::WaitId { want_stopped, .. } => want_stopped,
        }
    }

    const fn wants_continued(self) -> bool {
        match self {
            Self::Wait4 { want_continued, .. } => want_continued,
            Self::WaitId { want_continued, .. } => want_continued,
        }
    }

    fn write_result(self, thread: &Thread, outcome: WaitOutcome) -> LinuxResult<isize> {
        match self {
            Self::Wait4 { status_ptr, .. } => {
                thread.write_wait_status(status_ptr, outcome.status)?;
                Ok(outcome.pid as isize)
            }
            Self::WaitId { siginfo_ptr, .. } => {
                thread.write_waitid_siginfo(siginfo_ptr, outcome.pid, outcome.status)?;
                Ok(0)
            }
        }
    }
}

struct ReadyThreadQueue(UnsafeCell<axstd::vec::Vec<Thread>>);
unsafe impl Sync for ReadyThreadQueue {}

impl ReadyThreadQueue {
    fn with_mut<R>(&self, f: impl FnOnce(&mut axstd::vec::Vec<Thread>) -> R) -> R {
        unsafe { f(&mut *self.0.get()) }
    }

    fn enqueue_immediate(&self, thread: Thread) {
        self.with_mut(|queue| queue.push(thread));
    }

    fn enqueue_deferred(&self, thread: Thread) {
        self.with_mut(|queue| queue.insert(0, thread));
    }

    fn visit_mut<F>(&self, mut visit: F) -> bool
    where
        F: FnMut(&mut Thread) -> bool,
    {
        self.with_mut(|queue| {
            for thread in queue.iter_mut() {
                if visit(thread) {
                    return true;
                }
            }
            false
        })
    }

    fn is_empty(&self) -> bool {
        self.with_mut(|queue| queue.is_empty())
    }

    fn len(&self) -> usize {
        self.with_mut(|queue| queue.len())
    }

    fn pop_next(&self) -> Option<Thread> {
        self.with_mut(|queue| queue.pop())
    }

    fn remove_process_threads(&self, pid: Pid) {
        self.with_mut(|queue| queue.retain(|thread| thread.pid() != pid));
    }

    fn drain_process_threads(&self, pids: &[Pid], out: &mut Vec<Thread>, limit: usize) {
        self.with_mut(|queue| {
            let mut idx = 0usize;
            while idx < queue.len() && out.len() < limit {
                if sorted_pids_contain(pids, queue[idx].pid()) {
                    out.push(queue.remove(idx));
                } else {
                    idx += 1;
                }
            }
        });
    }
}

