/// `ext4-view` 的 reader 接口要求返回 `Error + Send + Sync`，而 `axstd::io::Error`
/// 不能直接放进去，因此这里做一个极薄的错误桥接。
#[derive(Debug, Clone, Copy)]
struct DiskReadError(axstd::io::Error);

impl fmt::Display for DiskReadError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}", self.0)
    }
}

impl core::error::Error for DiskReadError {}

impl Ext4Read for DiskReader {
    /// 按 ext4-view 约定从底层设备读取任意字节区间。
    fn read(
        &mut self,
        start_byte: u64,
        dst: &mut [u8],
    ) -> Result<(), Box<dyn core::error::Error + Send + Sync + 'static>> {
        self.disk.set_position(start_byte);

        let mut filled = 0;
        while filled < dst.len() {
            let read_len = self.disk.read_one(&mut dst[filled..]).map_err(|err| {
                Box::new(DiskReadError(map_dev_err(err)))
                    as Box<dyn core::error::Error + Send + Sync + 'static>
            })?;
            if read_len == 0 {
                return Err(Box::new(DiskReadError(axstd::io::Error::UnexpectedEof)));
            }
            filled += read_len;
        }
        Ok(())
    }
}

/// bring-up 阶段的 ext4 根盘提供者。
///
/// 这个类型代表“当前启动所看到的 ext4 评测根盘”，而不是系统级 VFS root。
#[derive(Clone)]
pub struct RootFsProvider {
    inner: Arc<Mutex<SerializedExt4>>,
}

/// `ext4-view` 内部使用 `Rc + RefCell`，天然不是 `Send`。
///
/// `vos` 当前仍是单核协作式调度；这里把真正的 `Ext4` 实例封装成“只能通过互斥锁串行
/// 调用”的内部状态，不把 `Ext4` 本体或它生成的 iterator 暴露到锁外。
///
/// 安全约束：
/// - 所有对 `Ext4` 的访问都必须经由 `RootFsProvider` 的方法串行化；
/// - 不允许把内部 `Ext4` 引用或 `read_dir` 迭代器泄漏到锁外。
struct SerializedExt4(Ext4);

unsafe impl Send for SerializedExt4 {}

impl SerializedExt4 {
    fn read(&mut self, path: &str) -> axstd::io::Result<Vec<u8>> {
        let metadata = self.metadata(path)?;
        if metadata.is_dir {
            return Err(axstd::io::Error::IsADirectory);
        }

        let mut data = axstd::vec![0; metadata.size as usize];
        let mut offset = 0usize;
        while offset < data.len() {
            let end = offset.saturating_add(EXT4_READ_CHUNK_SIZE).min(data.len());
            let read_len = self.read_at(path, offset as u64, &mut data[offset..end])?;
            if read_len == 0 {
                data.truncate(offset);
                break;
            }
            offset += read_len;
        }
        Ok(data)
    }

    fn read_to_string(&mut self, path: &str) -> axstd::io::Result<String> {
        String::from_utf8(self.read(path)?).map_err(|_| axstd::io::Error::InvalidInput)
    }

    fn read_at(&mut self, path: &str, offset: u64, buf: &mut [u8]) -> axstd::io::Result<usize> {
        let mut file = self.0.open(path).map_err(map_ext4_err)?;
        file.seek_to(offset).map_err(map_ext4_err)?;
        file.read_bytes(buf).map_err(map_ext4_err)
    }

    fn exists(&mut self, path: &str) -> axstd::io::Result<bool> {
        self.0.exists(path).map_err(map_ext4_err)
    }

    fn metadata(&mut self, path: &str) -> axstd::io::Result<RootFsMetadata> {
        let metadata = self.0.metadata(path).map_err(map_ext4_err)?;
        let file_type = metadata.file_type();
        Ok(RootFsMetadata {
            size: metadata.len(),
            mode: metadata.mode(),
            is_dir: metadata.is_dir(),
            is_regular_file: file_type.is_regular_file(),
        })
    }

    fn list_dir(&mut self, path: &str) -> axstd::io::Result<Vec<RootDirEntry>> {
        let iter = self.0.read_dir(path).map_err(map_ext4_err)?;
        let mut entries = Vec::new();
        for entry in iter {
            let entry = entry.map_err(map_ext4_err)?;
            let file_type = entry.file_type().map_err(map_ext4_err)?;
            entries.push(RootDirEntry {
                name: entry.file_name().display().to_string(),
                path: entry.path().display().to_string(),
                is_dir: file_type.is_dir(),
                is_regular_file: file_type.is_regular_file(),
            });
        }
        Ok(entries)
    }
}

impl RootFsProvider {
    /// 从启动阶段缓存下来的真实块设备构建只读 ext4 视图。
    pub fn new() -> axstd::io::Result<Self> {
        let disk = take_root_disk()?;
        let inner = Ext4::load(Box::new(DiskReader { disk })).map_err(map_ext4_err)?;
        Ok(Self {
            inner: Arc::new(Mutex::new(SerializedExt4(inner))),
        })
    }

    /// 列出 ext4 根目录条目，用于启动阶段确认评测盘是否读通。
