    pub fn read_at(&self, path: &str, offset: u64, buf: &mut [u8]) -> axstd::io::Result<usize> {
        self.inner.lock().read_at(path, offset, buf)
    }

    /// 判断某个绝对路径在 ext4 中是否存在。
    ///
    /// 第 6 步优先尝试 `/bin/<group_name>` 这一显式映射，再决定是否退到唯一候选程序，
    /// 因此需要一个轻量存在性探针，避免为了判断存在而把整份文件内容读入内存。
    pub fn exists(&self, path: &str) -> axstd::io::Result<bool> {
        self.inner.lock().exists(path)
    }

