        self.inner.lock().list_dir(path)
    }
}

/// 把启动阶段传入 `myfs` 的块设备缓存起来，供 ext4 bring-up 读取。
pub fn install_root_disk(disk: Disk) {
    if !ROOT_DISK.is_inited() {
        ROOT_DISK.init_once(Mutex::new(None));
    }
    *ROOT_DISK.lock() = Some(disk);
}

fn take_root_disk() -> axstd::io::Result<Disk> {
    if !ROOT_DISK.is_inited() {
        return Err(axstd::io::Error::NotFound);
    }
    ROOT_DISK.lock().take().ok_or(axstd::io::Error::NotFound)
}

/// 把 `ext4-view` 的错误压缩为当前 bring-up 足够用的 `axstd::io::Error`。
fn map_ext4_err(err: Ext4Error) -> axstd::io::Error {
    use axstd::io::Error;

    match err {
        Ext4Error::NotFound => Error::NotFound,
        Ext4Error::NotADirectory => Error::NotADirectory,
        Ext4Error::IsADirectory => Error::IsADirectory,
        Ext4Error::MalformedPath | Ext4Error::NotUtf8 => Error::InvalidInput,
        _ => Error::Io,
    }
}

