#[cfg(target_arch = "riscv64")]
const SAVED_FP_SLOT_FROM_FRAME_TOP: usize = size_of::<usize>();

#[cfg(target_arch = "loongarch64")]
const SAVED_FP_SLOT_FROM_FRAME_TOP: usize = size_of::<usize>() * 2;

/// 基于父线程 trap frame 准备子线程的初始用户态上下文。
///
/// 默认遵循原始 `clone(2)` 语义：子线程从 syscall 返回点继续执行，`a0 = 0`。
/// 若当前 trap frame 明显处在一个 frame-pointer 保护的活动调用帧中，则把这段活动帧整体
/// 搬到 `child_stack` 下方，并把“旧 `s0` 保存槽位”改写成新的子线程栈顶。这样子线程仍能
/// 继续走原来的 wrapper epilogue，但不再依赖固定的 `80/72` 常量。
fn build_clone_child_context(
    current: &Thread,
    tf: &TrapFrame,
    child_stack_top: usize,
