    let mut child_ctx = UspaceContext::from(tf);
    child_ctx.set_ip(crate::arch::next_syscall_ip(tf));
    child_ctx.set_retval(0);

    if let Some(frame_size) = infer_active_frame_size(tf) {
        let child_frame_sp = child_stack_top
            .checked_sub(frame_size)
            .ok_or(LinuxError::EINVAL)?;
        let frame_bytes = current.read_user_bytes(tf.regs.sp, frame_size)?;
        current.write_user_bytes(child_frame_sp, &frame_bytes)?;

        // 把 wrapper 保存的“旧 s0”改写成新的子线程逻辑帧顶。
        // 这样 wrapper epilogue 执行完后，调用者看到的是一套自洽的新栈坐标。
        let saved_fp_slot = child_stack_top
            .checked_sub(SAVED_FP_SLOT_FROM_FRAME_TOP)
            .ok_or(LinuxError::EINVAL)?;
        current.write_user_value(saved_fp_slot, &child_stack_top)?;

        child_ctx.set_sp(child_frame_sp);
        child_ctx.set_s0(child_stack_top);
    } else {
        child_ctx.set_sp(child_stack_top);
        child_ctx.set_s0(child_stack_top);
    }

    Ok(child_ctx)
}

