impl FutexDeadline {
    pub const fn new(deadline: Duration, realtime: bool) -> Self {
        Self { deadline, realtime }
    }

    pub fn is_expired(self) -> bool {
        let now = if self.realtime {
            axhal::time::wall_time()
        } else {
            axhal::time::monotonic_time()
        };
        now >= self.deadline
    }

    fn defer_from_now(&mut self, duration: Duration) {
        let now = if self.realtime {
            axhal::time::wall_time()
        } else {
            axhal::time::monotonic_time()
        };
        self.deadline = now.checked_add(duration).unwrap_or(now);
    }

    fn remaining(self) -> Duration {
        let now = if self.realtime {
            axhal::time::wall_time()
        } else {
            axhal::time::monotonic_time()
        };
        self.deadline.checked_sub(now).unwrap_or(Duration::ZERO)
    }

    fn monotonic_deadline_ns(self) -> u64 {
        let now_ns = axhal::time::monotonic_time_nanos();
        let remaining_ns = self.remaining().as_nanos().min(u64::MAX as u128) as u64;
        now_ns.saturating_add(remaining_ns)
    }
}

fn increment_timed_waiter_count() {
    FUTEX_TIMED_WAITER_COUNT.fetch_add(1, Ordering::Release);
}

fn decrement_timed_waiter_count() {
    let mut current = FUTEX_TIMED_WAITER_COUNT.load(Ordering::Acquire);
    loop {
        debug_assert!(current > 0, "timed futex waiter count underflow");
        if current == 0 {
            return;
        }
        match FUTEX_TIMED_WAITER_COUNT.compare_exchange_weak(
            current,
            current - 1,
            Ordering::AcqRel,
            Ordering::Acquire,
        ) {
            Ok(_) => return,
            Err(next) => current = next,
        }
    }
}

