pub const CLONE_FS: usize = 0x0000_0200;
pub const CLONE_FILES: usize = 0x0000_0400;
pub const CLONE_SIGHAND: usize = 0x0000_0800;
pub const CLONE_VFORK: usize = 0x0000_4000;
pub const CLONE_PARENT: usize = 0x0000_8000;
pub const CLONE_THREAD: usize = 0x0001_0000;
pub const CLONE_SYSVSEM: usize = 0x0004_0000;
pub const CLONE_SETTLS: usize = 0x0008_0000;
pub const CLONE_PARENT_SETTID: usize = 0x0010_0000;
pub const CLONE_CHILD_CLEARTID: usize = 0x0020_0000;
pub const CLONE_DETACHED: usize = 0x0040_0000;
pub const CLONE_CHILD_SETTID: usize = 0x0100_0000;
pub const CLONE_NEWNET: usize = 0x4000_0000;
pub const CLONE_IO: usize = 0x8000_0000;

/// musl pthread_create 要求的 flags 组合。
const SUPPORTED_CLONE_FLAGS: usize = CLONE_VM
    | CLONE_FS
    | CLONE_FILES
    | CLONE_SIGHAND
    | CLONE_THREAD
    | CLONE_SYSVSEM
    | CLONE_SETTLS
    | CLONE_PARENT_SETTID
    | CLONE_CHILD_CLEARTID
    | CLONE_DETACHED
    | CLONE_CHILD_SETTID
    | CLONE_NEWNET
    | CLONE_IO;
const CSIGNAL_MASK: usize = 0xff;

/// 校验 clone flags 是否全部受支持；不支持的 flags 返回 `EINVAL`。
pub fn validate_clone_flags(flags: usize) -> axerrno::LinuxResult {
    if flags & !(SUPPORTED_CLONE_FLAGS | CSIGNAL_MASK) != 0 {
        return Err(axerrno::LinuxError::EINVAL);
    }
    if flags & CLONE_THREAD != 0 && flags & CLONE_NEWNET != 0 {
        return Err(axerrno::LinuxError::EINVAL);
    }
    Ok(())
}

//! 把当前 ext4 只读观察器适配成 `axfs_vfs` 文件系统。
//!
//! 这一层先只承接第 1 步微重构：
//! - 复用已有 `RootFsProvider` 的只读能力；
//! - 把 ext4 中的根目录、普通文件和目录包装成 `VfsNodeOps`；
//! - 不改变上层当前“只读 ext4 + stdio 特判”的外部行为。

use axerrno::AxErrorKind;
use axfs_vfs::{
    VfsDirEntry, VfsNodeAttr, VfsNodeOps, VfsNodePerm, VfsNodeRef, VfsNodeType, VfsOps, VfsResult,
};
use axstd::string::String;
use axstd::sync::{Arc, Mutex};

use super::{RootDirEntry, RootFsProvider, ext4::RootFsMetadata};

const EXT4_FILE_BLOCK_SIZE: u64 = 512;

/// 当前 ext4 根盘的 VFS 适配器。
pub struct Ext4FileSystem {
    provider: RootFsProvider,
}

impl Ext4FileSystem {
    /// 用已有 `RootFsProvider` 构造只读 VFS 文件系统。
    pub fn new(provider: RootFsProvider) -> Arc<Self> {
        Arc::new(Self { provider })
    }

    fn lookup_path(&self, path: &str) -> VfsResult<VfsNodeRef> {
        lookup_provider_path(&self.provider, path)
    }

    pub fn exists(&self, path: &str) -> axstd::io::Result<bool> {
        self.provider.exists(path)
    }
}

impl VfsOps for Ext4FileSystem {
    fn root_dir(&self) -> VfsNodeRef {
        self.lookup_path("/")
            .expect("ext4 root directory must exist")
    }
}

struct Ext4FileNode {
    provider: RootFsProvider,
    path: String,
    size: u64,
    mode: u16,
}

impl VfsNodeOps for Ext4FileNode {
    axfs_vfs::impl_vfs_non_dir_default! {}

    fn get_attr(&self) -> VfsResult<VfsNodeAttr> {
        Ok(VfsNodeAttr::new(
            VfsNodePerm::from_bits_truncate(self.mode),
            VfsNodeType::File,
            self.size,
            blocks_for_size(self.size),
        ))
    }

    fn read_at(&self, offset: u64, buf: &mut [u8]) -> VfsResult<usize> {
        if offset >= self.size {
            return Ok(0);
        }
        self.provider
            .read_at(&self.path, offset, buf)
            .map_err(map_io_err_to_ax)
    }
}

struct Ext4DirNode {
    provider: RootFsProvider,
    path: String,
    mode: u16,
    cached_entries: Mutex<Option<axstd::vec::Vec<RootDirEntry>>>,
}

impl Ext4DirNode {
    fn new(provider: RootFsProvider, path: String, mode: u16) -> Self {
        Self {
            provider,
            path,
            mode,
            cached_entries: Mutex::new(None),
        }
    }

    fn snapshot_entries(&self) -> VfsResult<axstd::vec::Vec<RootDirEntry>> {
        let mut cached_entries = self.cached_entries.lock();
        if cached_entries.is_none() {
            *cached_entries = Some(
                self.provider
                    .list_dir(&self.path)
                    .map_err(map_io_err_to_ax)?,
            );
        }
        Ok(cached_entries
            .as_ref()
            .expect("ext4 dir cache should be populated after list_dir")
            .clone())
    }
}

impl VfsNodeOps for Ext4DirNode {
    axfs_vfs::impl_vfs_dir_default! {}

    fn get_attr(&self) -> VfsResult<VfsNodeAttr> {
        let entries = self.snapshot_entries()?;
        Ok(VfsNodeAttr::new(
            VfsNodePerm::from_bits_truncate(self.mode),
            VfsNodeType::Dir,
            entries.len() as u64,
            0,
        ))
    }

    fn parent(&self) -> Option<VfsNodeRef> {
        if self.path == "/" {
            return None;
        }
        lookup_provider_path(&self.provider, &parent_path(&self.path)).ok()
    }

    fn lookup(self: Arc<Self>, path: &str) -> VfsResult<VfsNodeRef> {
        let path = path.trim_matches('/');
        if path.is_empty() || path == "." {
            return Ok(self);
        }
        if path == ".." {
            return match self.parent() {
                Some(parent) => Ok(parent),
                None => Err(AxErrorKind::NotFound),
            };
        }
        let full_path = join_path(&self.path, path);
        lookup_provider_path(&self.provider, &full_path)
    }

    fn read_dir(&self, start_idx: usize, dirents: &mut [VfsDirEntry]) -> VfsResult<usize> {
        let entries = self.snapshot_entries()?;
        let mut written = 0;
        for entry in entries.into_iter().skip(start_idx) {
            if written >= dirents.len() {
                break;
            }
            let ty = if entry.is_dir {
                VfsNodeType::Dir
            } else {
                VfsNodeType::File
            };
            dirents[written] = VfsDirEntry::new(&entry.name, ty);
            written += 1;
        }
        Ok(written)
    }
}

fn normalize_vfs_path(path: &str) -> String {
    let trimmed = path.trim();
    if trimmed.is_empty() || trimmed == "/" {
        return "/".into();
    }

    let mut normalized = String::from("/");
    normalized.push_str(trimmed.trim_start_matches('/'));
    normalized
}

fn lookup_provider_path(provider: &RootFsProvider, path: &str) -> VfsResult<VfsNodeRef> {
    let normalized = normalize_vfs_path(path);
    let metadata = provider.metadata(&normalized).map_err(map_io_err_to_ax)?;
    node_from_metadata(provider, normalized, metadata)
}

fn node_from_metadata(
    provider: &RootFsProvider,
    path: String,
    metadata: RootFsMetadata,
) -> VfsResult<VfsNodeRef> {
    if metadata.is_dir {
        return Ok(Arc::new(Ext4DirNode::new(
            provider.clone(),
            path,
            metadata.mode,
        )));
    }
    Ok(Arc::new(Ext4FileNode {
        provider: provider.clone(),
        path,
        size: metadata.size,
        mode: metadata.mode,
    }))
}

fn join_path(base: &str, child: &str) -> String {
    if base == "/" {
        format!("/{}", child.trim_start_matches('/'))
    } else {
        format!(
            "{}/{}",
            base.trim_end_matches('/'),
            child.trim_start_matches('/')
        )
    }
}

fn parent_path(path: &str) -> String {
    if path == "/" {
        return "/".into();
    }
    let parent = path
        .rsplit_once('/')
        .map(|(prefix, _)| prefix)
        .unwrap_or("");
    if parent.is_empty() {
        "/".into()
    } else {
        parent.into()
    }
}

fn blocks_for_size(size: u64) -> u64 {
    size.div_ceil(EXT4_FILE_BLOCK_SIZE)
}

fn map_io_err_to_ax(err: axstd::io::Error) -> AxErrorKind {
    use axstd::io::Error;

    match err {
        Error::NotFound => AxErrorKind::NotFound,
        Error::InvalidInput => AxErrorKind::InvalidInput,
        Error::IsADirectory => AxErrorKind::IsADirectory,
        Error::NotADirectory => AxErrorKind::NotADirectory,
        Error::StorageFull => AxErrorKind::NoMemory,
        _ => AxErrorKind::Io,
    }
}

//! 最小 `/proc` 文件系统。
//!
//! 这里只实现 design 里 step 5/6 需要的最小只读视图：
//! - `/proc/mounts`
//! - `/proc/cpuinfo`
//! - `/proc/meminfo`
//! - `/proc/self/mounts`
//! - `/proc/self/mountinfo`
//! - `/proc/self/stat`
//! - `/proc/self/status`
//! - `/proc/self/oom_score_adj`
//! - `/proc/self/timerslack_ns`
//! - `/proc/self/timens_offsets`
//! - `/proc/self/maps`
//! - `/proc/self/smaps`
//! - `/proc/self/task`
//! - `/proc/[pid]/fdinfo/[fd]`
//! - `/proc/[pid]/task/[tid]/status`
//! - `/proc/sys/{fs,kernel}/*` minimal compatibility leaves
//!
//! `/proc/self` 绑定打开时的线程快照，普通文本内容仍在 read 时按最新
//! `ProcSnapshot` 即时渲染；`maps/smaps` 这类大文本则在单次 open 生命周期内缓存，
//! 避免顺序小块读取时重复全量重建。

use axfs_vfs::VfsError;
use axfs_vfs::{
    VfsDirEntry, VfsNodeAttr, VfsNodeOps, VfsNodePerm, VfsNodeRef, VfsNodeType, VfsOps, VfsResult,
};
use axhal::cpu_num;
use axhal::percpu::this_cpu_id;
use axstd::string::{String, ToString};
use axstd::sync::{Arc, Mutex};
use axstd::vec::Vec;
use core::sync::atomic::{AtomicU8, AtomicUsize, Ordering};

use crate::{
    fs::{MountAtimeMode, MountInfo, VfsRoot},
    task::{
        CurrentThread, LockedRange, MmapRegion, Pid, ProcFdInfo, ProcSnapshot, Process, Thread,
        Tid, TimeNsOffsets, UserVmLayout, render_proc_comm, render_proc_stat,
        render_proc_status,
    },
};

#[cfg(target_arch = "riscv64")]
const PROC_CPUINFO_ARCH: &str = "riscv64";

#[cfg(target_arch = "loongarch64")]
const PROC_CPUINFO_ARCH: &str = "loongarch64";
const PROC_SYS_OSTYPE: &str = "Linux\n";
const PROC_SYS_OSRELEASE: &str = "6.6.0\n";
const PROC_SYS_VERSION: &str = "#1 vos\n";
const PROC_SYS_TAINTED: &str = "0\n";
const PROC_SYS_PID_MAX: &str = "4194304\n";
const PROC_SYS_CORE_PATTERN: &str = "core\n";
const PROC_SYS_PIPE_MAX_SIZE_DEFAULT: usize = 64 * 1024;
const PROC_SYS_NET_IPV4_CONF_TAG_DEFAULT: usize = 0;
const PROC_SYS_DOMAINNAME_DEFAULT: &[u8] = b"localdomain";
const PROC_SYS_DOMAINNAME_MAX: usize = 64;
static PROC_SYS_SCHED_AUTOGROUP_ENABLED: AtomicU8 = AtomicU8::new(0);
static PROC_SYS_PIPE_MAX_SIZE: AtomicUsize = AtomicUsize::new(PROC_SYS_PIPE_MAX_SIZE_DEFAULT);
static PROC_SYS_NET_IPV4_CONF_DEFAULT_TAG: AtomicUsize =
    AtomicUsize::new(PROC_SYS_NET_IPV4_CONF_TAG_DEFAULT);
static PROC_SYS_DOMAINNAME: Mutex<ProcSysString> = Mutex::new(ProcSysString::uninitialized());

struct ProcSysString {
    bytes: [u8; PROC_SYS_DOMAINNAME_MAX],
    len: usize,
    initialized: bool,
}

impl ProcSysString {
    const fn uninitialized() -> Self {
        Self {
            bytes: [0; PROC_SYS_DOMAINNAME_MAX],
            len: 0,
            initialized: false,
        }
    }

    fn ensure_initialized(&mut self) {
        if !self.initialized {
            self.set(PROC_SYS_DOMAINNAME_DEFAULT);
        }
    }

    fn set(&mut self, value: &[u8]) {
        let value = trim_ascii_whitespace(value);
        let len = value.len().min(PROC_SYS_DOMAINNAME_MAX);
        self.bytes = [0; PROC_SYS_DOMAINNAME_MAX];
        self.bytes[..len].copy_from_slice(&value[..len]);
        self.len = len;
        self.initialized = true;
    }

    fn render(&mut self) -> String {
        self.ensure_initialized();
        let mut value = String::from(core::str::from_utf8(&self.bytes[..self.len]).unwrap_or(""));
        value.push('\n');
        value
    }
}

