#[derive(Clone, Copy)]
enum SysDirKind {
    Root,
    Kernel,
    Devices,
    DevicesSystem,
    Cpu,
    Fs,
    Ext4,
}

struct SysDirNode {
    kind: SysDirKind,
}

impl SysDirNode {
    fn new(kind: SysDirKind) -> Arc<Self> {
        Arc::new(Self { kind })
    }

    fn child(&self, name: &str) -> VfsResult<VfsNodeRef> {
        match self.kind {
            SysDirKind::Root => match name {
                "." | "" => Ok(Self::new(SysDirKind::Root)),
                ".." => axfs_vfs::__priv::ax_err!(NotFound),
                "kernel" => Ok(Self::new(SysDirKind::Kernel)),
                "devices" => Ok(Self::new(SysDirKind::Devices)),
                "fs" => Ok(Self::new(SysDirKind::Fs)),
                _ => axfs_vfs::__priv::ax_err!(NotFound),
            },
            SysDirKind::Kernel => match name {
                "." | "" => Ok(Self::new(SysDirKind::Kernel)),
                ".." => Ok(Self::new(SysDirKind::Root)),
                "ostype" => Ok(Arc::new(SysFileNode::new("Linux\n"))),
                "osrelease" => Ok(Arc::new(SysFileNode::new("vos\n"))),
                _ => axfs_vfs::__priv::ax_err!(NotFound),
            },
            SysDirKind::Devices => match name {
                "." | "" => Ok(Self::new(SysDirKind::Devices)),
                ".." => Ok(Self::new(SysDirKind::Root)),
                "system" => Ok(Self::new(SysDirKind::DevicesSystem)),
                _ => axfs_vfs::__priv::ax_err!(NotFound),
            },
            SysDirKind::DevicesSystem => match name {
                "." | "" => Ok(Self::new(SysDirKind::DevicesSystem)),
                ".." => Ok(Self::new(SysDirKind::Devices)),
                "cpu" => Ok(Self::new(SysDirKind::Cpu)),
                _ => axfs_vfs::__priv::ax_err!(NotFound),
            },
            SysDirKind::Cpu => match name {
                "." | "" => Ok(Self::new(SysDirKind::Cpu)),
                ".." => Ok(Self::new(SysDirKind::DevicesSystem)),
                "online" => Ok(Arc::new(SysFileNode::new("0\n"))),
                _ => axfs_vfs::__priv::ax_err!(NotFound),
            },
            SysDirKind::Fs => match name {
                "." | "" => Ok(Self::new(SysDirKind::Fs)),
                ".." => Ok(Self::new(SysDirKind::Root)),
                "ext4" => Ok(Self::new(SysDirKind::Ext4)),
                _ => axfs_vfs::__priv::ax_err!(NotFound),
            },
            SysDirKind::Ext4 => match name {
                "." | "" => Ok(Self::new(SysDirKind::Ext4)),
                ".." => Ok(Self::new(SysDirKind::Fs)),
                "ro" => Ok(Arc::new(SysFileNode::new("1\n"))),
                _ => axfs_vfs::__priv::ax_err!(NotFound),
            },
        }
    }

    fn dir_entries(&self) -> &'static [(&'static str, VfsNodeType)] {
        match self.kind {
            SysDirKind::Root => &[
                ("kernel", VfsNodeType::Dir),
                ("devices", VfsNodeType::Dir),
                ("fs", VfsNodeType::Dir),
            ],
            SysDirKind::Kernel => &[
                ("ostype", VfsNodeType::File),
                ("osrelease", VfsNodeType::File),
            ],
            SysDirKind::Devices => &[("system", VfsNodeType::Dir)],
            SysDirKind::DevicesSystem => &[("cpu", VfsNodeType::Dir)],
            SysDirKind::Cpu => &[("online", VfsNodeType::File)],
            SysDirKind::Fs => &[("ext4", VfsNodeType::Dir)],
            SysDirKind::Ext4 => &[("ro", VfsNodeType::File)],
        }
    }
}

impl VfsNodeOps for SysDirNode {
    axfs_vfs::impl_vfs_dir_default! {}

    fn get_attr(&self) -> VfsResult<VfsNodeAttr> {
        Ok(VfsNodeAttr::new(
            VfsNodePerm::from_bits_truncate(0o555),
            VfsNodeType::Dir,
            0,
            0,
        ))
    }

    fn lookup(self: Arc<Self>, path: &str) -> VfsResult<VfsNodeRef> {
        let (name, rest) = split_path(path);
        let node = self.child(name)?;
        if let Some(rest) = rest {
            node.lookup(rest)
        } else {
            Ok(node)
        }
    }

    fn read_dir(&self, start_idx: usize, dirents: &mut [VfsDirEntry]) -> VfsResult<usize> {
        let entries = self.dir_entries();
        let mut written = 0;
        for (name, ty) in entries.iter().skip(start_idx) {
            if written >= dirents.len() {
                break;
            }
            dirents[written] = VfsDirEntry::new(*name, *ty);
            written += 1;
        }
        Ok(written)
    }
}

struct SysFileNode {
    content: &'static str,
}

impl SysFileNode {
    const fn new(content: &'static str) -> Self {
        Self { content }
    }
}

impl VfsNodeOps for SysFileNode {
    axfs_vfs::impl_vfs_non_dir_default! {}

    fn get_attr(&self) -> VfsResult<VfsNodeAttr> {
        Ok(VfsNodeAttr::new(
            VfsNodePerm::from_bits_truncate(0o444),
            VfsNodeType::File,
            self.content.len() as u64,
            (self.content.len() as u64).div_ceil(512),
        ))
    }

    fn read_at(&self, offset: u64, buf: &mut [u8]) -> VfsResult<usize> {
        let bytes = self.content.as_bytes();
        let start = bytes.len().min(offset as usize);
        let end = bytes.len().min(start + buf.len());
        let src = &bytes[start..end];
        buf[..src.len()].copy_from_slice(src);
        Ok(src.len())
    }
}

fn split_path(path: &str) -> (&str, Option<&str>) {
    let trimmed = path.trim_start_matches('/');
    trimmed.find('/').map_or((trimmed, None), |n| {
        (&trimmed[..n], Some(&trimmed[n + 1..]))
    })
}

