fn seccomp_violation_signal(current: &Thread, syscall_nr: usize) -> Option<i32> {
    match current.process().prctl_compat_state().seccomp_mode {
        SECCOMP_MODE_DISABLED => None,
        SECCOMP_MODE_STRICT => {
            if matches!(
                syscall_nr,
                READ_SYSCALL
                    | WRITE_SYSCALL
                    | crate::user::EXIT_SYSCALL
                    | signal::RT_SIGRETURN_SYSCALL
            ) {
                None
            } else {
                Some(SIGKILL)
            }
        }
        SECCOMP_MODE_FILTER => {
            if matches!(
                syscall_nr,
                WAITID_SYSCALL
                    | signal::RT_SIGPROCMASK_SYSCALL
                    | CLOSE_SYSCALL
                    | crate::user::EXIT_SYSCALL
                    | WAIT4_SYSCALL
                    | WRITE_SYSCALL
                    | thread::CLONE_SYSCALL
            ) {
                None
            } else {
                Some(SIGSYS)
            }
        }
        _ => Some(SIGKILL),
    }
}

