fn validate_futex_addr(current: &Thread, addr: usize) -> Result<(), LinuxError> {
    if addr == 0 || addr & (core::mem::size_of::<u32>() - 1) != 0 {
        return Err(LinuxError::EINVAL);
    }
    let _: u32 = current.read_user_value(addr)?;
    Ok(())
}

fn validate_futex_requeue_counts(
    wake_count: usize,
    requeue_count: usize,
) -> Result<(), LinuxError> {
    if (wake_count as isize) < 0 || (requeue_count as isize) < 0 {
        return Err(LinuxError::EINVAL);
    }
    Ok(())
}

fn read_futex_deadline(
    current: &Thread,
    timeout_ptr: usize,
    absolute: bool,
    realtime: bool,
) -> Result<Option<futex::FutexDeadline>, LinuxError> {
    if timeout_ptr == 0 {
        return Ok(None);
    }
    let timeout = current.read_user_value::<super::LinuxTimespec>(timeout_ptr)?;
    let duration = timeout.to_duration()?;
    let deadline = if absolute {
        if realtime {
            super::time::realtime_absolute_to_raw_wall_deadline(duration)?
        } else {
            duration
        }
    } else {
        let base = if realtime {
            axhal::time::wall_time()
        } else {
            axhal::time::monotonic_time()
        };
        base.checked_add(duration).ok_or(LinuxError::EINVAL)?
    };
    Ok(Some(futex::FutexDeadline::new(deadline, realtime)))
}

/// 处理 `futex(2)`。
///
/// 当前支持 FUTEX_WAIT / FUTEX_WAIT_BITSET / FUTEX_WAKE / FUTEX_REQUEUE。
pub(super) fn syscall_futex(
    mut current: Thread,
    tf: &TrapFrame,
    trap_stack_top: VirtAddr,
    args: [usize; 6],
) -> super::SyscallReturn {
    let uaddr = args[0];
    let op = args[1] as i32;
    let val = args[2];
    let arg3 = args[3];
    let uaddr2 = args[4];
    let bitset = args[5] as u32;
    let cmd = op & FUTEX_CMD_MASK;

    match cmd {
        futex::FUTEX_WAIT => {
            let expected = val as u32;
            let deadline =
                match read_futex_deadline(&current, arg3, false, op & FUTEX_CLOCK_REALTIME != 0) {
                    Ok(deadline) => deadline,
                    Err(err) => return Err((current, err)),
                };
            match futex::futex_wait(&current, uaddr, expected) {
                Ok(true) => {
                    if deadline.is_some_and(|deadline| deadline.is_expired()) {
                        return Err((current, LinuxError::ETIMEDOUT));
                    }
                    // 值匹配，阻塞当前线程。
                    // 和 wait4 一样，这里要保存“syscall 即将返回”的用户态现场；
                    // 被 futex_wake 唤醒后，线程应当从 ecall 下一条指令继续，且返回值为 0。
                    current.capture_syscall_context(tf);
                    current.set_user_retval(0);
                    crate::task::ltp_trace::trace_futex_wait(
                        &current,
                        uaddr,
                        cmd,
                        expected,
                        deadline.is_some(),
                    );
                    futex::park_futex_waiter(uaddr, deadline, current);
                    unsafe { crate::task::schedule_next_ready(trap_stack_top) }
                }
                Ok(false) => {
                    // 值不匹配，返回 EAGAIN。
                    Err((current, axerrno::LinuxError::EAGAIN))
                }
                Err(err) => Err((current, err)),
            }
        }
        futex::FUTEX_WAIT_BITSET => {
            if bitset == 0 {
                return Err((current, LinuxError::EINVAL));
            }
            let deadline =
                match read_futex_deadline(&current, arg3, true, op & FUTEX_CLOCK_REALTIME != 0) {
                    Ok(deadline) => deadline,
                    Err(err) => return Err((current, err)),
                };
            if bitset != FUTEX_BITSET_MATCH_ANY {
                println!("user syscall: futex wait_bitset using non-match-any bitset={bitset:#x}");
            }
            match futex::futex_wait(&current, uaddr, val as u32) {
                Ok(true) => {
                    if deadline.is_some_and(|deadline| deadline.is_expired()) {
                        return Err((current, LinuxError::ETIMEDOUT));
                    }
                    current.capture_syscall_context(tf);
                    current.set_user_retval(0);
                    crate::task::ltp_trace::trace_futex_wait(
                        &current,
                        uaddr,
                        cmd,
                        val as u32,
                        deadline.is_some(),
                    );
                    futex::park_futex_waiter(uaddr, deadline, current);
                    unsafe { crate::task::schedule_next_ready(trap_stack_top) }
                }
                Ok(false) => Err((current, LinuxError::EAGAIN)),
                Err(err) => Err((current, err)),
            }
        }
        futex::FUTEX_WAKE => {
            let woken = futex::futex_wake(uaddr, val);
            crate::task::ltp_trace::trace_futex_wake(&current, uaddr, val, woken);
            Ok((current, woken))
        }
        futex::FUTEX_REQUEUE => {
            if let Err(err) = validate_futex_addr(&current, uaddr2) {
                return Err((current, err));
            }
            let requeue_count = arg3;
            if let Err(err) = validate_futex_requeue_counts(val, requeue_count) {
                return Err((current, err));
            }
            match futex::futex_requeue(uaddr, uaddr2, val, requeue_count) {
                Ok(affected) => {
                    println!(
                        "user syscall: futex requeue src={uaddr:#x} dst={uaddr2:#x} wake={val} requeue={requeue_count} affected={affected}"
                    );
                    Ok((current, affected))
                }
                Err(err) => Err((current, err)),
            }
        }
        futex::FUTEX_CMP_REQUEUE => {
            if let Err(err) = validate_futex_addr(&current, uaddr2) {
                return Err((current, err));
            }
            let cmp = bitset;
            let current_value = match current.read_user_value::<u32>(uaddr) {
                Ok(value) => value,
                Err(err) => return Err((current, err)),
            };
            if current_value != cmp {
                return Err((current, LinuxError::EAGAIN));
            }
            let requeue_count = arg3;
            if let Err(err) = validate_futex_requeue_counts(val, requeue_count) {
                return Err((current, err));
            }
            match futex::futex_requeue(uaddr, uaddr2, val, requeue_count) {
                Ok(affected) => Ok((current, affected)),
                Err(err) => Err((current, err)),
            }
        }
        _ => {
            println!("user syscall: futex unsupported op={op}");
            Err((current, axerrno::LinuxError::ENOSYS))
        }
    }
}

//! 比赛 bring-up 的最小启动控制流。
//!
//! 当前阶段把启动编排收敛到一条最窄的比赛闭环：
//! 1. 挂载 ext4 评测盘并列出根目录条目，确认根盘可读；
//! 2. 从根目录或官方 runtime 目录枚举可识别的测试组；
//! 3. 对每个测试组按顺序装载并执行对应用户程序；
//! 4. 直接 ELF 组由内核补打比赛要求的 `START/END` 标记；
//! 5. 每组子程序 `exit` 后恢复父线程拿到 `wait4` 返回，再由内核 continuation 决定继续下一组或关机。
